import{_ as e,o,c as a,ag as r}from"./chunks/framework.OsDJF_Ea.js";const c=JSON.parse('{"title":"Your First Patch","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/first-patch.md","filePath":"getting-started/first-patch.md"}'),s={name:"getting-started/first-patch.md"};function n(l,t,i,d,h,p){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="your-first-patch" tabindex="-1">Your First Patch <a class="header-anchor" href="#your-first-patch" aria-label="Permalink to &quot;Your First Patch&quot;">​</a></h1><p>This walkthrough builds a simple patch: an oscillator through a filter, controlled by a pot, output to speakers. It takes about two minutes.</p><h2 id="step-1-add-an-oscillator" tabindex="-1">Step 1: Add an Oscillator <a class="header-anchor" href="#step-1-add-an-oscillator" aria-label="Permalink to &quot;Step 1: Add an Oscillator&quot;">​</a></h2><p>Open the <strong>module palette</strong> (the panel on the left, or tap the + button on mobile). Find <strong>Oscillator</strong> under Sound Sources and click it. A module node appears on the canvas.</p><p>The oscillator generates a tone. By default it produces a 440 Hz saw wave.</p><h2 id="step-2-add-a-filter" tabindex="-1">Step 2: Add a Filter <a class="header-anchor" href="#step-2-add-a-filter" aria-label="Permalink to &quot;Step 2: Add a Filter&quot;">​</a></h2><p>From the palette, add a <strong>Filter</strong> (under Effects). Position it to the right of the oscillator.</p><h2 id="step-3-add-the-output" tabindex="-1">Step 3: Add the Output <a class="header-anchor" href="#step-3-add-the-output" aria-label="Permalink to &quot;Step 3: Add the Output&quot;">​</a></h2><p>Add a <strong>Stereo Out</strong> (under Hardware I/O). This is the module that sends audio to the DAC and your speakers/headphones.</p><h2 id="step-4-connect-them" tabindex="-1">Step 4: Connect Them <a class="header-anchor" href="#step-4-connect-them" aria-label="Permalink to &quot;Step 4: Connect Them&quot;">​</a></h2><ol><li>Click and drag from the Oscillator&#39;s <strong>L</strong> output port to the Filter&#39;s <strong>inL</strong> input port. A cable appears.</li><li>Drag from the Filter&#39;s <strong>lpL</strong> output to the Stereo Out&#39;s <strong>L</strong> input.</li><li>Drag from the Filter&#39;s <strong>lpR</strong> output to the Stereo Out&#39;s <strong>R</strong> input.</li></ol><p>You now have: <strong>Oscillator -&gt; Filter -&gt; Stereo Out</strong></p><h2 id="step-5-add-a-pot-for-cutoff-control" tabindex="-1">Step 5: Add a Pot for Cutoff Control <a class="header-anchor" href="#step-5-add-a-pot-for-cutoff-control" aria-label="Permalink to &quot;Step 5: Add a Pot for Cutoff Control&quot;">​</a></h2><p>Add a <strong>Pot</strong> module (under Hardware I/O). Connect its <strong>out</strong> port to the Filter&#39;s <strong>cutoff</strong> input. This maps one of the hardware potentiometers to the filter cutoff frequency.</p><h2 id="step-6-upload" tabindex="-1">Step 6: Upload <a class="header-anchor" href="#step-6-upload" aria-label="Permalink to &quot;Step 6: Upload&quot;">​</a></h2><p>Click the <strong>Upload</strong> button in the toolbar. The patch JSON is sent to the board over USB. Within a second, you should hear the oscillator playing through the filter. Turn the physical pot to sweep the filter cutoff.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li>Try changing the oscillator waveform -- click the Oscillator node to open its inspector, then draw a waveform or select a preset.</li><li>Add a <strong>VCA</strong> between the filter and output, controlled by a <strong>Button</strong> with an <strong>ADSR</strong> envelope.</li><li>Explore the <a href="/docs/modules/">Module Reference</a> to see what else is available.</li><li>Read <a href="/docs/guides/signal-flow.html">Signal Flow</a> to understand how audio and control signals work.</li></ul>',18)])])}const f=e(s,[["render",n]]);export{c as __pageData,f as default};
